/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const N = nums.length;

    // 1. Preprocessing: Prefix sum for even numbers count
    // P[i] stores the count of even numbers in nums[0...i-1]
    const P = new Array(N + 1).fill(0);
    for (let i = 0; i < N; i++) {
        P[i + 1] = P[i] + (nums[i] % 2 === 0 ? 1 : 0);
    }

    /**
     * Helper function to find the index of the last element <= X in nums.
     * Returns -1 if all elements are > X.
     * Implements upper_bound logic adapted for 0-based indexing.
     * @param {number} X
     * @returns {number} R'
     */
    const findLastIndexLeq = (X) => {
        let low = 0;
        let high = N - 1;
        let result = -1;

        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (nums[mid] <= X) {
                result = mid;
                low = mid + 1; // Try to find a larger index
            } else {
                high = mid - 1; // Too large
            }
        }
        return result;
    };

    const results = [];

    for (const query of queries) {
        const l = query[0];
        const r = query[1];
        const k = query[2];

        // Binary search for J, where the answer X = 2J.
        // We seek the smallest J such that J - C(2J) >= k.

        // Lower bound for J: J must be at least k (if C(2J)=0).
        let L = k; 
        // Upper bound for J: Maximum possible C is N. J <= k + N.
        let R = k + N + 1; 
        let bestJ = R;

        while (L <= R) {
            const J = Math.floor((L + R) / 2);
            const X = 2 * J;

            // Step 1: Find R', the largest index such that nums[R'] <= X
            const R_prime = findLastIndexLeq(X);

            // Step 2: Determine the effective upper bound for counting
            // We only care about indices i in [l, r] AND nums[i] <= X.
            // This means i must be in [l, min(r, R_prime)].
            const R_eff = Math.min(r, R_prime);

            // Step 3: Calculate C(X) = count of even numbers in nums[l...R_eff]
            let C_X = 0;
            if (R_eff >= l) {
                // P[i+1] - P[l] gives count in range [l, i]
                C_X = P[R_eff + 1] - P[l];
            }

            // Step 4: Check condition
            // Number of remaining evens <= X is J - C(X)
            if (J - C_X >= k) {
                // J is potentially the answer, try smaller J
                bestJ = J;
                R = J - 1;
            } else {
                // J is too small, need larger J
                L = J + 1;
            }
        }

        // The result is 2 * bestJ
        results.push(2 * bestJ);
    }

    return results;
